import { useState, useCallback, useEffect, useRef, memo } from 'react'
import ReactMarkdown from 'react-markdown'
import remarkGfm from 'remark-gfm'
import type {
  ChatMessage,
  ContentBlock,
  TextBlock,
  ToolCallBlock,
  ToolResultBlock,
  ImageBlock,
  HtmlBlock,
  Annotation,
} from '../types/message'
import type { ForkableMessage, ForkPoint } from '../types/session'
import { ImageAnnotator, annotationsToPrompt } from './ImageAnnotator'
import type { ImageAnnotatorHandle } from './ImageAnnotator'
import type { ViewMode } from '../utils/compact-view'
import { groupByTurns, getUserSummary, getAgentSummary } from '../utils/compact-view'
import type { ConversationTurn } from '../utils/compact-view'

interface ChatViewProps {
  messages: ChatMessage[]
  isStreaming: boolean
  streamingMessageId: string | null
  onSendPrompt: (text: string, images?: { data: string; mimeType: string }[]) => void
  pendingUiRequests: Array<{ id: string; method: string; [key: string]: unknown }>
  respondToUiRequest: (requestId: string, response: Record<string, unknown>) => void
  onForkAtEntry: (entryId: string, name: string) => void
  getForkMessages: () => Promise<ForkableMessage[]>
  forkPoints: ForkPoint[]
  viewMode: ViewMode
}

function TextBlockRenderer({ block, isStreaming }: { block: TextBlock; isStreaming?: boolean }): React.ReactElement {
  // During streaming, skip expensive ReactMarkdown parsing to reduce flicker.
  // Use lightweight <pre>-based rendering; switch to full markdown once stable.
  if (isStreaming) {
    return (
      <div className="prose prose-sm max-w-none whitespace-pre-wrap break-words text-sm leading-relaxed">
        {block.content}
        <span className="inline-block w-1.5 h-4 ml-0.5 bg-gray-400 animate-pulse align-text-bottom" />
      </div>
    )
  }
  return (
    <div className="prose prose-sm max-w-none">
      <ReactMarkdown remarkPlugins={[remarkGfm]}>{block.content}</ReactMarkdown>
    </div>
  )
}

const ToolCallRenderer = memo(function ToolCallRenderer({ block }: { block: ToolCallBlock }): React.ReactElement {
  const statusColors: Record<ToolCallBlock['status'], string> = {
    pending: 'text-gray-500',
    running: 'text-yellow-600',
    completed: 'text-green-600',
    error: 'text-red-500',
  }

  const statusIcons: Record<ToolCallBlock['status'], string> = {
    pending: '\u25CB',
    running: '\u25D4',
    completed: '\u25CF',
    error: '\u2717',
  }

  return (
    <details className="rounded border border-gray-200 bg-gray-50">
      <summary className="cursor-pointer px-3 py-2 text-sm">
        <span className={statusColors[block.status]}>{statusIcons[block.status]}</span>
        {' '}
        <span className="font-mono text-xs text-gray-700">{block.toolName}</span>
        {block.toolName === 'bash' && block.args.command && (
          <span className="ml-2 font-mono text-xs text-gray-400">
            {String(block.args.command).substring(0, 60)}
            {String(block.args.command).length > 60 ? '...' : ''}
          </span>
        )}
      </summary>
      <div className="border-t border-gray-200 px-3 py-2">
        <pre className="overflow-x-auto text-xs text-gray-600">
          {JSON.stringify(block.args, null, 2)}
        </pre>
      </div>
    </details>
  )
})

function ToolResultRenderer({ block }: { block: ToolResultBlock }): React.ReactElement {
  return (
    <div className="space-y-2 rounded border border-gray-200 bg-gray-50/50 px-3 py-2">
      {block.content.map((child, i) => {
        if (child.type === 'text') {
          return (
            <pre key={i} className="overflow-x-auto whitespace-pre-wrap text-xs text-gray-600">
              {(child as TextBlock).content}
            </pre>
          )
        }
        if (child.type === 'image') {
          return <ImageBlockRenderer key={i} block={child as ImageBlock} />
        }
        if (child.type === 'html') {
          return <HtmlBlockRenderer key={i} block={child as HtmlBlock} />
        }
        return null
      })}
    </div>
  )
}

function HtmlBlockRenderer({ block }: { block: HtmlBlock }): React.ReactElement {
  const [expanded, setExpanded] = useState(true)
  const iframeRef = useRef<HTMLIFrameElement>(null)

  const handleLoad = useCallback(() => {
    if (!iframeRef.current) return
    const doc = iframeRef.current.contentDocument
    if (!doc?.body) return
    const height = doc.body.scrollHeight
    iframeRef.current.style.height = `${Math.min(Math.max(height, 100), 600)}px`
  }, [])

  return (
    <div className="my-2 overflow-hidden rounded border border-gray-200">
      <div className="flex items-center justify-between bg-gray-100 px-3 py-1.5">
        <span className="text-xs font-medium text-gray-500">
          {block.title ?? 'HTML Preview'}
        </span>
        <button
          onClick={() => setExpanded(!expanded)}
          className="text-xs text-gray-400 hover:text-gray-600"
        >
          {expanded ? 'Collapse' : 'Expand'}
        </button>
      </div>
      {expanded && (
        <iframe
          ref={iframeRef}
          srcDoc={block.content}
          sandbox="allow-scripts allow-same-origin"
          onLoad={handleLoad}
          className="w-full border-0 bg-white"
          style={{ height: '300px' }}
          title={block.title ?? 'HTML Preview'}
        />
      )}
    </div>
  )
}

interface AnnotatableImageBlockProps {
  block: ImageBlock
  messageId: string
  blockIndex: number
  isAnnotating: boolean
  onEnterAnnotation: () => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
}

function AnnotatableImageBlock({
  block,
  messageId,
  blockIndex,
  isAnnotating,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
}: AnnotatableImageBlockProps): React.ReactElement {
  const [annotations, setAnnotations] = useState<Annotation[]>([])
  const [isFullscreen, setIsFullscreen] = useState(false)
  const [zoom, setZoom] = useState(1)
  const annotatorRef = useRef<ImageAnnotatorHandle>(null)

  void messageId
  void blockIndex

  const handleWheel = useCallback((e: React.WheelEvent) => {
    e.preventDefault()
    setZoom((prev) => Math.max(0.25, Math.min(4, prev + (e.deltaY > 0 ? -0.15 : 0.15))))
  }, [])

  useEffect(() => {
    if (!isFullscreen) return
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setIsFullscreen(false)
        setZoom(1)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [isFullscreen])

  const handleSendFeedback = useCallback(() => {
    if (!annotatorRef.current) return
    const result = annotatorRef.current.getAnnotatedImage()
    if (!result) return

    const base64Match = result.dataUrl.match(/^data:image\/png;base64,(.+)$/)
    if (!base64Match) return

    onSendFeedback(result.description, base64Match[1])
    onExitAnnotation()
  }, [onSendFeedback, onExitAnnotation])

  if (isAnnotating) {
    return (
      <div className="my-2 overflow-hidden rounded border border-blue-600">
        <ImageAnnotator
          ref={annotatorRef}
          src={block.src}
          alt={block.alt}
          annotations={annotations}
          onAnnotationsChange={setAnnotations}
          isActive={true}
        />
        <div className="flex items-center justify-between border-t border-blue-600 bg-gray-100 px-3 py-2">
          <span className="text-xs text-gray-600">
            {annotations.length} annotation{annotations.length !== 1 ? 's' : ''}
          </span>
          <div className="flex gap-2">
            <button
              onClick={onExitAnnotation}
              className="rounded bg-gray-200 px-3 py-1 text-xs font-medium text-gray-700 hover:bg-gray-300"
            >
              Cancel
            </button>
            <button
              onClick={handleSendFeedback}
              className="rounded bg-blue-600 px-3 py-1 text-xs font-medium text-white hover:bg-blue-500"
            >
              Send Feedback
            </button>
          </div>
        </div>
      </div>
    )
  }

  if (isFullscreen) {
    return (
      <div
        className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
        onClick={() => {
          setIsFullscreen(false)
          setZoom(1)
        }}
      >
        <img
          src={block.src}
          alt={block.alt ?? 'image'}
          style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }}
          className="max-h-[90vh] max-w-[90vw] cursor-zoom-out transition-transform"
          onWheel={handleWheel}
          onClick={(e) => e.stopPropagation()}
        />
        <div className="absolute bottom-4 right-4 flex gap-2">
          <button
            onClick={(e) => {
              e.stopPropagation()
              setZoom((z) => Math.min(4, z + 0.25))
            }}
            className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white hover:bg-gray-700"
          >
            +
          </button>
          <span className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white">
            {Math.round(zoom * 100)}%
          </span>
          <button
            onClick={(e) => {
              e.stopPropagation()
              setZoom((z) => Math.max(0.25, z - 0.25))
            }}
            className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white hover:bg-gray-700"
          >
            -
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation()
              setIsFullscreen(false)
              setZoom(1)
            }}
            className="rounded bg-red-800/80 px-3 py-1 text-sm text-white hover:bg-red-700"
          >
            ESC
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="my-2 overflow-hidden rounded border border-gray-200">
      <div className="relative group">
        <img
          src={block.src}
          alt={block.alt ?? 'image'}
          className="max-w-full cursor-zoom-in transition-opacity hover:opacity-90"
          onClick={() => setIsFullscreen(true)}
          loading="lazy"
        />
        <button
          onClick={onEnterAnnotation}
          className="absolute top-2 right-2 rounded bg-blue-600/90 px-2 py-1 text-xs font-medium text-white opacity-0 transition-opacity hover:bg-blue-500 group-hover:opacity-100"
        >
          Annotate
        </button>
      </div>
      {block.alt && (
        <div className="border-t border-gray-200 bg-gray-50 px-2 py-1 text-xs text-gray-500">
          {block.alt}
        </div>
      )}
    </div>
  )
}

const ContentBlockRenderer = memo(function ContentBlockRenderer({
  block,
  messageId,
  blockIndex,
  isStreamingBlock,
  annotatingTarget,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
}: {
  block: ContentBlock
  messageId: string
  blockIndex: number
  isStreamingBlock?: boolean
  annotatingTarget: { messageId: string; blockIndex: number } | null
  onEnterAnnotation: (messageId: string, blockIndex: number) => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
}): React.ReactElement | null {
  switch (block.type) {
    case 'text':
      return <TextBlockRenderer block={block} isStreaming={isStreamingBlock} />
    case 'tool_call':
      return <ToolCallRenderer block={block} />
    case 'tool_result':
      return <ToolResultRenderer block={block} />
    case 'image':
      return (
        <AnnotatableImageBlock
          block={block}
          messageId={messageId}
          blockIndex={blockIndex}
          isAnnotating={
            annotatingTarget !== null &&
            annotatingTarget.messageId === messageId &&
            annotatingTarget.blockIndex === blockIndex
          }
          onEnterAnnotation={() => onEnterAnnotation(messageId, blockIndex)}
          onExitAnnotation={onExitAnnotation}
          onSendFeedback={onSendFeedback}
        />
      )
    case 'action':
      return <div className="text-xs text-yellow-600">[Action: {block.actionType}]</div>
    case 'html':
      return <HtmlBlockRenderer block={block} />
    default:
      return null
  }
})

function ForkNameInput({
  onForkAtEntry,
  onClose,
  defaultEntryId,
}: {
  onForkAtEntry: (entryId: string, name: string) => void
  onClose: () => void
  defaultEntryId: string
}): React.ReactElement {
  const popoverRef = useRef<HTMLDivElement>(null)
  const [forkName, setForkName] = useState('')

  useEffect(() => {
    function handleClickOutside(e: MouseEvent): void {
      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
        onClose()
      }
    }
    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [onClose])

  const handleConfirm = useCallback(() => {
    if (forkName.trim()) {
      onForkAtEntry(defaultEntryId, forkName.trim())
      onClose()
    }
  }, [forkName, defaultEntryId, onForkAtEntry, onClose])

  return (
    <div
      ref={popoverRef}
      className="absolute right-0 top-8 z-30 w-64 rounded-lg border border-gray-200 bg-white shadow-xl"
    >
      <div className="px-3 py-2 space-y-1.5">
        <input
          autoFocus
          value={forkName}
          onChange={(e) => setForkName(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') handleConfirm()
            if (e.key === 'Escape') onClose()
          }}
          placeholder="Fork session name"
          className="w-full rounded border border-gray-300 bg-white px-2 py-1 text-xs text-gray-900 outline-none focus:border-blue-500"
        />
        <button
          onClick={handleConfirm}
          disabled={!forkName.trim()}
          className="w-full rounded bg-blue-600 px-2 py-1 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
        >
          Fork from here
        </button>
      </div>
    </div>
  )
}

function TurnCard({
  turn,
  isLast,
  isExpanded,
  onToggleExpand,
  annotatingTarget,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
  onForkClick,
  forkInputMessageId,
  forkEntryId,
  onForkClose,
  onForkAtEntry,
  forkPoints,
  isStreaming,
  streamingMessageId,
}: {
  turn: ConversationTurn
  isLast: boolean
  isExpanded: boolean
  onToggleExpand: () => void
  annotatingTarget: { messageId: string; blockIndex: number } | null
  onEnterAnnotation: (messageId: string, blockIndex: number) => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
  onForkClick: (messageId: string, piEntryId: string | undefined) => void
  forkInputMessageId: string | null
  forkEntryId: string | null
  onForkClose: () => void
  onForkAtEntry: (entryId: string, name: string) => void
  forkPoints: ForkPoint[]
  isStreaming: boolean
  streamingMessageId: string | null
}): React.ReactElement {
  const userSummary = getUserSummary(turn.userMessage)
  const agentSummary = getAgentSummary(turn.assistantMessages)

  if (isExpanded) {
    const allMessages = [turn.userMessage, ...turn.assistantMessages]
    return (
      <div className="flex">
        <div className="flex flex-col items-center w-6 flex-shrink-0">
          <div className="w-2.5 h-2.5 rounded-full bg-blue-500 border-2 border-blue-500 mt-3 flex-shrink-0" />
          {!isLast && <div className="w-px flex-1 bg-gray-200" />}
        </div>
        <div className="flex-1 border-l-[3px] border-blue-500 bg-blue-50/30 rounded-r-lg ml-1">
          <div className="flex items-center justify-end px-3 py-1">
            <button
              onClick={onToggleExpand}
              className="rounded px-2 py-0.5 text-xs text-gray-500 hover:text-gray-700 hover:bg-gray-100 transition-colors"
            >
              Collapse
            </button>
          </div>
          <div className="space-y-4 px-4 pb-4">
            {allMessages.map((msg) => {
              const msgForkPoints = forkPoints.filter((fp) => fp.entryId === msg.piEntryId)
              return (
                <div
                  key={msg.id}
                  className={`group relative rounded-lg px-4 py-3 ${
                    msg.role === 'user' ? 'bg-blue-50' : 'bg-gray-50'
                  }`}
                >
                  <div className="mb-1 flex items-center justify-between">
                    <span className="text-xs font-medium text-gray-500">
                      {msg.role === 'user' ? 'You' : 'Pi'}
                    </span>
                    <div className="relative">
                      <button
                        onClick={() => onForkClick(msg.id, msg.piEntryId)}
                        className="rounded px-2 py-0.5 text-xs text-gray-400 opacity-0 transition-opacity hover:text-gray-600 hover:bg-gray-100 group-hover:opacity-100"
                      >
                        Fork
                      </button>
                      {forkInputMessageId === msg.id && forkEntryId && (
                        <ForkNameInput
                          onForkAtEntry={onForkAtEntry}
                          onClose={onForkClose}
                          defaultEntryId={forkEntryId}
                        />
                      )}
                    </div>
                  </div>
                  <div className="space-y-2">
                    {msg.blocks.map((block, i) => (
                      <ContentBlockRenderer
                        key={i}
                        block={block}
                        messageId={msg.id}
                        blockIndex={i}
                        isStreamingBlock={isStreaming && streamingMessageId === msg.id && block.type === 'text'}
                        annotatingTarget={annotatingTarget}
                        onEnterAnnotation={onEnterAnnotation}
                        onExitAnnotation={onExitAnnotation}
                        onSendFeedback={onSendFeedback}
                      />
                    ))}
                  </div>
                  {msgForkPoints.length > 0 && (
                    <div className="mt-2 flex flex-wrap gap-1.5 border-t border-gray-200/50 pt-2">
                      {msgForkPoints.map((fp, idx) => (
                        <span
                          key={idx}
                          className="inline-flex items-center gap-1 rounded-full bg-purple-100 px-2 py-0.5 text-[10px] text-purple-700"
                        >
                          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                            <path strokeLinecap="round" strokeLinejoin="round" d="M13 17h8m0 0V9m0 8l-8-8-4 4-6-6" />
                          </svg>
                          forked: {fp.childName || '(unnamed)'}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="flex">
      <div className="flex flex-col items-center w-6 flex-shrink-0">
        <div className="w-2.5 h-2.5 rounded-full bg-white border-2 border-gray-300 mt-2.5 flex-shrink-0 cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-colors" onClick={onToggleExpand} />
        {!isLast && <div className="w-px flex-1 bg-gray-200" />}
      </div>
      <div
        className="flex-1 cursor-pointer rounded-lg border border-gray-200 bg-white px-4 py-2.5 hover:bg-gray-50 transition-colors ml-1"
        onClick={onToggleExpand}
      >
        <div className="text-sm text-gray-800">{userSummary}</div>
        <div className="mt-0.5 text-sm text-gray-500 pl-4">
          <span className="mr-1 text-gray-400">{'\u2192'}</span>
          {agentSummary || '...'}
        </div>
      </div>
    </div>
  )
}

function OutlineRow({
  turn,
  isLast,
  isExpanded,
  onToggleExpand,
  annotatingTarget,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
  onForkClick,
  forkInputMessageId,
  forkEntryId,
  onForkClose,
  onForkAtEntry,
  forkPoints,
  isStreaming,
  streamingMessageId,
}: {
  turn: ConversationTurn
  isLast: boolean
  isExpanded: boolean
  onToggleExpand: () => void
  annotatingTarget: { messageId: string; blockIndex: number } | null
  onEnterAnnotation: (messageId: string, blockIndex: number) => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
  onForkClick: (messageId: string, piEntryId: string | undefined) => void
  forkInputMessageId: string | null
  forkEntryId: string | null
  onForkClose: () => void
  onForkAtEntry: (entryId: string, name: string) => void
  forkPoints: ForkPoint[]
  isStreaming: boolean
  streamingMessageId: string | null
}): React.ReactElement {
  const userSummary = getUserSummary(turn.userMessage)

  if (isExpanded) {
    const allMessages = [turn.userMessage, ...turn.assistantMessages]
    return (
      <div className="flex">
        <div className="flex flex-col items-center w-6 flex-shrink-0">
          <div className="w-2.5 h-2.5 rounded-full bg-blue-500 border-2 border-blue-500 mt-3 flex-shrink-0" />
          {!isLast && <div className="w-px flex-1 bg-gray-200" />}
        </div>
        <div className="flex-1 border-l-[3px] border-blue-500 bg-blue-50/30 rounded-r-lg ml-1">
          <div className="flex items-center justify-between px-3 py-1">
            <span className="text-xs text-gray-400">#{turn.index}</span>
            <button
              onClick={onToggleExpand}
              className="rounded px-2 py-0.5 text-xs text-gray-500 hover:text-gray-700 hover:bg-gray-100 transition-colors"
            >
              Collapse
            </button>
          </div>
          <div className="space-y-4 px-4 pb-4">
            {allMessages.map((msg) => {
              const msgForkPoints = forkPoints.filter((fp) => fp.entryId === msg.piEntryId)
              return (
                <div
                  key={msg.id}
                  className={`group relative rounded-lg px-4 py-3 ${
                    msg.role === 'user' ? 'bg-blue-50' : 'bg-gray-50'
                  }`}
                >
                  <div className="mb-1 flex items-center justify-between">
                    <span className="text-xs font-medium text-gray-500">
                      {msg.role === 'user' ? 'You' : 'Pi'}
                    </span>
                    <div className="relative">
                      <button
                        onClick={() => onForkClick(msg.id, msg.piEntryId)}
                        className="rounded px-2 py-0.5 text-xs text-gray-400 opacity-0 transition-opacity hover:text-gray-600 hover:bg-gray-100 group-hover:opacity-100"
                      >
                        Fork
                      </button>
                      {forkInputMessageId === msg.id && forkEntryId && (
                        <ForkNameInput
                          onForkAtEntry={onForkAtEntry}
                          onClose={onForkClose}
                          defaultEntryId={forkEntryId}
                        />
                      )}
                    </div>
                  </div>
                  <div className="space-y-2">
                    {msg.blocks.map((block, i) => (
                      <ContentBlockRenderer
                        key={i}
                        block={block}
                        messageId={msg.id}
                        blockIndex={i}
                        isStreamingBlock={isStreaming && streamingMessageId === msg.id && block.type === 'text'}
                        annotatingTarget={annotatingTarget}
                        onEnterAnnotation={onEnterAnnotation}
                        onExitAnnotation={onExitAnnotation}
                        onSendFeedback={onSendFeedback}
                      />
                    ))}
                  </div>
                  {msgForkPoints.length > 0 && (
                    <div className="mt-2 flex flex-wrap gap-1.5 border-t border-gray-200/50 pt-2">
                      {msgForkPoints.map((fp, idx) => (
                        <span
                          key={idx}
                          className="inline-flex items-center gap-1 rounded-full bg-purple-100 px-2 py-0.5 text-[10px] text-purple-700"
                        >
                          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                            <path strokeLinecap="round" strokeLinejoin="round" d="M13 17h8m0 0V9m0 8l-8-8-4 4-6-6" />
                          </svg>
                          forked: {fp.childName || '(unnamed)'}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="flex">
      <div className="flex flex-col items-center w-6 flex-shrink-0">
        <div className="w-2.5 h-2.5 rounded-full bg-white border-2 border-gray-300 mt-1.5 flex-shrink-0 cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-colors" onClick={onToggleExpand} />
        {!isLast && <div className="w-px flex-1 bg-gray-200" />}
      </div>
      <div
        className="flex-1 cursor-pointer rounded px-3 py-1.5 hover:bg-gray-50 transition-colors ml-1"
        onClick={onToggleExpand}
      >
        <span className="text-xs text-gray-400 mr-2 font-mono">{turn.index}</span>
        <span className="text-sm text-gray-800">{userSummary}</span>
      </div>
    </div>
  )
}

function ChatView({ messages, isStreaming, streamingMessageId, onSendPrompt, pendingUiRequests, respondToUiRequest, onForkAtEntry, getForkMessages, forkPoints, viewMode }: ChatViewProps): React.ReactElement {
  const bottomRef = useRef<HTMLDivElement>(null)
  const [annotatingTarget, setAnnotatingTarget] = useState<{
    messageId: string
    blockIndex: number
  } | null>(null)
  const [forkInputMessageId, setForkInputMessageId] = useState<string | null>(null)
  const [forkEntryId, setForkEntryId] = useState<string | null>(null)
  const [expandedTurns, setExpandedTurns] = useState<Set<string>>(new Set())

  const handleEnterAnnotation = useCallback((messageId: string, blockIndex: number) => {
    setAnnotatingTarget({ messageId, blockIndex })
  }, [])

  const handleExitAnnotation = useCallback(() => {
    setAnnotatingTarget(null)
  }, [])

  const handleSendFeedback = useCallback(
    (description: string, imageData: string) => {
      onSendPrompt(description, [{ data: imageData, mimeType: 'image/png' }])
      setAnnotatingTarget(null)
    },
    [onSendPrompt],
  )

  const handleForkClick = useCallback(async (messageId: string, piEntryId: string | undefined) => {
    if (forkInputMessageId === messageId) {
      setForkInputMessageId(null)
      setForkEntryId(null)
      return
    }
    if (piEntryId) {
      setForkEntryId(piEntryId)
    } else {
      const msgs = await getForkMessages()
      const lastMsg = msgs[msgs.length - 1]
      setForkEntryId(lastMsg?.entryId ?? null)
    }
    setForkInputMessageId(messageId)
  }, [forkInputMessageId, getForkMessages])

  const toggleTurn = useCallback((turnId: string) => {
    setExpandedTurns((prev) => {
      const next = new Set(prev)
      if (next.has(turnId)) {
        next.delete(turnId)
      } else {
        next.add(turnId)
      }
      return next
    })
  }, [])

  const handleForkClose = useCallback(() => {
    setForkInputMessageId(null)
    setForkEntryId(null)
  }, [])

  // Throttled scroll: only scroll on animation frames to avoid jank
  const scrollRafRef = useRef<number | null>(null)
  useEffect(() => {
    if (scrollRafRef.current !== null) cancelAnimationFrame(scrollRafRef.current)
    scrollRafRef.current = requestAnimationFrame(() => {
      scrollRafRef.current = null
      bottomRef.current?.scrollIntoView({ behavior: isStreaming ? 'auto' : 'smooth' })
    })
    return () => {
      if (scrollRafRef.current !== null) cancelAnimationFrame(scrollRafRef.current)
    }
  }, [messages, isStreaming])

  const turns = viewMode !== 'normal' ? groupByTurns(messages) : []

  return (
    <div className="flex-1 overflow-y-auto bg-white px-4 py-6">
      {messages.length === 0 ? (
        <div className="flex h-full items-center justify-center">
          <div className="text-center">
            <p className="text-lg text-gray-400">Start a conversation with Pi</p>
            <p className="mt-2 text-sm text-gray-400">Type a message below or connect to Pi first</p>
          </div>
        </div>
      ) : viewMode === 'normal' ? (
        <div className="mx-auto max-w-3xl space-y-4">
          {messages.map((msg) => {
            const msgForkPoints = forkPoints.filter((fp) => fp.entryId === msg.piEntryId)

            return (
              <div
                key={msg.id}
                className={`group relative rounded-lg px-4 py-3 ${
                  msg.role === 'user'
                    ? 'bg-blue-50'
                    : 'bg-gray-50'
                }`}
              >
                <div className="mb-1 flex items-center justify-between">
                  <span className="text-xs font-medium text-gray-500">
                    {msg.role === 'user' ? 'You' : 'Pi'}
                  </span>
                  <div className="relative">
                    <button
                      onClick={() => handleForkClick(msg.id, msg.piEntryId)}
                      className="rounded px-2 py-0.5 text-xs text-gray-400 opacity-0 transition-opacity hover:text-gray-600 hover:bg-gray-100 group-hover:opacity-100"
                    >
                      Fork
                    </button>
                    {forkInputMessageId === msg.id && forkEntryId && (
                      <ForkNameInput
                        onForkAtEntry={onForkAtEntry}
                        onClose={() => { setForkInputMessageId(null); setForkEntryId(null) }}
                        defaultEntryId={forkEntryId}
                      />
                    )}
                  </div>
                </div>
                <div className="space-y-2">
                  {msg.blocks.map((block, i) => (
                    <ContentBlockRenderer
                      key={i}
                      block={block}
                      messageId={msg.id}
                      blockIndex={i}
                      isStreamingBlock={isStreaming && streamingMessageId === msg.id && block.type === 'text'}
                      annotatingTarget={annotatingTarget}
                      onEnterAnnotation={handleEnterAnnotation}
                      onExitAnnotation={handleExitAnnotation}
                      onSendFeedback={handleSendFeedback}
                    />
                  ))}
                </div>
                {msgForkPoints.length > 0 && (
                  <div className="mt-2 flex flex-wrap gap-1.5 border-t border-gray-200/50 pt-2">
                    {msgForkPoints.map((fp, idx) => (
                      <span
                        key={idx}
                        className="inline-flex items-center gap-1 rounded-full bg-purple-100 px-2 py-0.5 text-[10px] text-purple-700"
                      >
                        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                          <path strokeLinecap="round" strokeLinejoin="round" d="M13 17h8m0 0V9m0 8l-8-8-4 4-6-6" />
                        </svg>
                        forked: {fp.childName || '(unnamed)'}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            )
          })}
          <div ref={bottomRef} />
        </div>
      ) : viewMode === 'turn' ? (
        <div className="mx-auto max-w-3xl space-y-0">
          {turns.map((turn, idx) => (
            <TurnCard
              key={turn.id}
              turn={turn}
              isLast={idx === turns.length - 1}
              isExpanded={expandedTurns.has(turn.id)}
              onToggleExpand={() => toggleTurn(turn.id)}
              annotatingTarget={annotatingTarget}
              onEnterAnnotation={handleEnterAnnotation}
              onExitAnnotation={handleExitAnnotation}
              onSendFeedback={handleSendFeedback}
              onForkClick={handleForkClick}
              forkInputMessageId={forkInputMessageId}
              forkEntryId={forkEntryId}
              onForkClose={handleForkClose}
              onForkAtEntry={onForkAtEntry}
              forkPoints={forkPoints}
              isStreaming={isStreaming}
              streamingMessageId={streamingMessageId}
            />
          ))}
          <div ref={bottomRef} />
        </div>
      ) : (
        <div className="mx-auto max-w-3xl space-y-0">
          {turns.map((turn, idx) => (
            <OutlineRow
              key={turn.id}
              turn={turn}
              isLast={idx === turns.length - 1}
              isExpanded={expandedTurns.has(turn.id)}
              onToggleExpand={() => toggleTurn(turn.id)}
              annotatingTarget={annotatingTarget}
              onEnterAnnotation={handleEnterAnnotation}
              onExitAnnotation={handleExitAnnotation}
              onSendFeedback={handleSendFeedback}
              onForkClick={handleForkClick}
              forkInputMessageId={forkInputMessageId}
              forkEntryId={forkEntryId}
              onForkClose={handleForkClose}
              onForkAtEntry={onForkAtEntry}
              forkPoints={forkPoints}
              isStreaming={isStreaming}
              streamingMessageId={streamingMessageId}
            />
          ))}
          <div ref={bottomRef} />
        </div>
      )}
    </div>
  )
}

export default ChatView

import { useState, useCallback, useEffect, useRef } from 'react'
import type { SessionListResult, SessionInfo, SessionTreeNode } from '../types/session'

interface SessionSidebarProps {
  sessions: SessionListResult | null
  currentSession: SessionInfo | null
  onSwitchSession: (sessionPath: string) => void
  onNewSession: (name: string) => void
  onRenameSession: (name: string) => void
  onDeleteSession: (sessionPath: string) => Promise<boolean>
  onSetSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<boolean>
  onForkFromEnd: (sessionPath: string, name: string) => void
  isCollapsed: boolean
  onToggleCollapse: () => void
}

function formatRelativeTime(isoTimestamp: string): string {
  const now = Date.now()
  const then = new Date(isoTimestamp).getTime()
  const diffMs = now - then
  const diffMin = Math.floor(diffMs / 60000)
  const diffHr = Math.floor(diffMs / 3600000)
  const diffDay = Math.floor(diffMs / 86400000)

  if (diffMin < 1) return 'just now'
  if (diffMin < 60) return `${diffMin}m ago`
  if (diffHr < 24) return `${diffHr}h ago`
  if (diffDay < 30) return `${diffDay}d ago`
  return new Date(isoTimestamp).toLocaleDateString()
}

function getDisplayName(session: SessionInfo): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

const SLOT_W = 16
const LINE_LEFT = 8
const R = 3
const GRAY = '#e5e7eb'
const BLUE = '#3b82f6'

function isDescendantOf(node: SessionTreeNode, sessionPath: string | null): boolean {
  if (!sessionPath) return false
  if (node.session.filePath === sessionPath) return true
  return node.children.some((child) => isDescendantOf(child, sessionPath))
}

function GuideLine({ highlight }: { highlight: boolean }) {
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{ left: LINE_LEFT, top: 0, bottom: 0, width: 1.5, backgroundColor: highlight ? BLUE : GRAY }}
      />
    </div>
  )
}

function GuideBranch({ active, highlight }: { active: boolean; highlight?: boolean }) {
  const color = active ? BLUE : GRAY
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none overflow-visible"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{ left: LINE_LEFT, top: 0, height: `calc(50% - ${R}px)`, width: 1.5, backgroundColor: color }}
      />
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: `calc(50% - ${R}px)`,
          width: R,
          height: R,
          borderLeft: `1.5px solid ${color}`,
          borderBottom: `1.5px solid ${color}`,
          borderBottomLeftRadius: R,
        }}
      />
      <div
        className="absolute"
        style={{
          left: LINE_LEFT + R,
          top: `calc(50% - 1.5px)`,
          width: SLOT_W - LINE_LEFT - R + 3,
          height: 1.5,
          backgroundColor: color,
        }}
      />
      <div
        className="absolute"
        style={{ left: LINE_LEFT, top: '50%', bottom: 0, width: 1.5, backgroundColor: GRAY }}
      />
      {highlight && (
        <div
          className="absolute"
          style={{ left: LINE_LEFT, top: 0, bottom: 0, width: 1.5, backgroundColor: BLUE }}
        />
      )}
    </div>
  )
}

function GuideElbow({ active }: { active: boolean }) {
  const color = active ? BLUE : GRAY
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none overflow-visible"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{ left: LINE_LEFT, top: 0, height: `calc(50% - ${R}px)`, width: 1.5, backgroundColor: color }}
      />
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: `calc(50% - ${R}px)`,
          width: R,
          height: R,
          borderLeft: `1.5px solid ${color}`,
          borderBottom: `1.5px solid ${color}`,
          borderBottomLeftRadius: R,
        }}
      />
      <div
        className="absolute"
        style={{
          left: LINE_LEFT + R,
          top: `calc(50% - 1.5px)`,
          width: SLOT_W - LINE_LEFT - R + 3,
          height: 1.5,
          backgroundColor: color,
        }}
      />
    </div>
  )
}

function GuideSlot() {
  return (
    <div
      className="flex-shrink-0"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    />
  )
}

function DotSlot({
  active,
  hasChildren,
  isExpanded,
  highlight,
  completed,
}: {
  active: boolean
  hasChildren: boolean
  isExpanded: boolean
  highlight: boolean
  completed: boolean
}) {
  return (
    <div
      className="flex-shrink-0 flex items-center justify-center relative"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className={
          active
            ? 'w-2.5 h-2.5 rounded-full bg-blue-500 border-2 border-blue-500 flex-shrink-0'
            : completed
              ? 'w-2.5 h-2.5 rounded-full bg-gray-300 border-2 border-gray-300 flex-shrink-0'
              : 'w-2.5 h-2.5 rounded-full bg-white border-2 border-gray-300 group-hover:border-blue-500 flex-shrink-0'
        }
      />
      {hasChildren && isExpanded && (
        <div
          className="absolute"
          style={{
            left: LINE_LEFT,
            top: 'calc(50% + 5px)',
            bottom: 0,
            width: 1.5,
            backgroundColor: highlight ? BLUE : GRAY,
          }}
        />
      )}
    </div>
  )
}

function SessionNode({
  node,
  ancestorLines,
  currentSessionPath,
  isOnActivePath,
  onSwitch,
  onRename,
  onDelete,
  onSetSessionStatus,
  onForkFromEnd,
  onContextMenu,
  triggerRenamePath,
  onRenameTriggered,
  triggerForkPath,
  onForkTriggered,
}: {
  node: SessionTreeNode
  ancestorLines: { hasLine: boolean; highlight: boolean; branchActive: boolean }[]
  currentSessionPath: string | null
  isOnActivePath: boolean
  onSwitch: (path: string) => void
  onRename: (name: string) => void
  onDelete: (path: string) => Promise<boolean>
  onSetSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<boolean>
  onForkFromEnd: (sessionPath: string, name: string) => void
  onContextMenu: (e: React.MouseEvent, session: SessionInfo) => void
  triggerRenamePath: string | null
  onRenameTriggered: () => void
  triggerForkPath: string | null
  onForkTriggered: () => void
}): React.ReactElement {
  const [isExpanded, setIsExpanded] = useState(true)
  const [isRenaming, setIsRenaming] = useState(false)
  const [renameValue, setRenameValue] = useState(getDisplayName(node.session))
  const [confirmDelete, setConfirmDelete] = useState(false)
  const [isForking, setIsForking] = useState(false)
  const [forkName, setForkName] = useState('')
  const isCompleted = node.session.status === 'completed'
  const isActive = currentSessionPath === node.session.filePath
  const hasChildren = node.children.length > 0

  useEffect(() => {
    if (triggerRenamePath === node.session.filePath) {
      setIsRenaming(true)
      setRenameValue(getDisplayName(node.session))
      onRenameTriggered()
    }
  }, [triggerRenamePath, node.session.filePath, onRenameTriggered])

  useEffect(() => {
    if (triggerForkPath === node.session.filePath) {
      setIsForking(true)
      setForkName('')
      onForkTriggered()
    }
  }, [triggerForkPath, node.session.filePath, onForkTriggered])

  const handleDoubleClick = useCallback(() => {
    setIsRenaming(true)
    setRenameValue(getDisplayName(node.session))
  }, [node.session])

  const handleRenameSubmit = useCallback(() => {
    const trimmed = renameValue.trim()
    if (trimmed && trimmed !== getDisplayName(node.session)) {
      onRename(trimmed)
    }
    setIsRenaming(false)
  }, [renameValue, node.session, onRename])

  const hasChildOnActivePath = node.children.some(
    (child) =>
      currentSessionPath === child.session.filePath ||
      isDescendantOf(child, currentSessionPath)
  )

  const renderGuides = () => {
    if (ancestorLines.length === 0) return null
    return ancestorLines.map((entry, i) => {
      const isConnector = i === ancestorLines.length - 1
      if (isConnector) {
        if (entry.hasLine) {
          return <GuideBranch key={i} active={entry.branchActive} highlight={entry.highlight && !entry.branchActive} />
        }
        return <GuideElbow key={i} active={entry.branchActive} />
      }
      if (entry.hasLine) {
        return <GuideLine key={i} highlight={entry.highlight && !entry.branchActive} />
      }
      return <GuideSlot key={i} />
    })
  }

  return (
    <div>
      <div
        className={`group flex items-center rounded cursor-pointer transition-colors ${
          isActive
            ? isCompleted
              ? 'bg-gray-100 text-gray-400'
              : 'bg-gray-100 text-gray-900'
            : isCompleted
              ? 'text-gray-400 hover:bg-gray-100/60 hover:text-gray-500'
              : 'text-gray-600 hover:bg-gray-100/60 hover:text-gray-800'
        }`}
        onClick={() => onSwitch(node.session.filePath)}
        onDoubleClick={handleDoubleClick}
        onContextMenu={(e) => onContextMenu(e, node.session)}
      >
        {renderGuides()}
        <DotSlot
          active={isOnActivePath || isActive || node.session.isMain}
          hasChildren={hasChildren}
          isExpanded={isExpanded}
          highlight={hasChildOnActivePath}
          completed={isCompleted}
        />
        <div className="flex-1 flex items-center gap-1 py-1.5 pr-2 min-w-0">
          {isRenaming ? (
            <input
              autoFocus
              value={renameValue}
              onChange={(e) => setRenameValue(e.target.value)}
              onBlur={handleRenameSubmit}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleRenameSubmit()
                if (e.key === 'Escape') setIsRenaming(false)
              }}
              onClick={(e) => e.stopPropagation()}
              className="flex-1 min-w-0 bg-gray-100 rounded px-1 py-0.5 text-xs text-gray-900 outline-none border border-gray-300 focus:border-blue-500"
            />
          ) : (
            <span className={`flex-1 truncate text-xs ${isCompleted ? 'line-through' : ''}`}>
              {getDisplayName(node.session)}
            </span>
          )}

          <span className="flex-shrink-0 text-[10px] text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
            {formatRelativeTime(node.session.createdAt)}
          </span>

          {hasChildren && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsExpanded(!isExpanded)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title={isExpanded ? 'Collapse' : 'Expand'}
            >
              <svg
                className={`w-3 h-3 transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                fill="currentColor"
                viewBox="0 0 20 20"
              >
                <path
                  fillRule="evenodd"
                  d="M7.21 14.77a.75.75 0 01.02-1.06L11.168 10 7.23 6.29a.75.75 0 111.04-1.08l4.5 4.25a.75.75 0 010 1.08l-4.5 4.25a.75.75 0 01-1.06-.02z"
                  clipRule="evenodd"
                />
              </svg>
            </button>
          )}

          {node.session.parentSessionPath && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                onSwitch(node.session.parentSessionPath!)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Go to parent session"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
              </svg>
            </button>
          )}

          {isActive && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsForking(true)
                setForkName('')
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-purple-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Fork"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 12h4m6 0h4M12 5v4m0 6v4" />
                <circle cx="5" cy="12" r="2" />
                <circle cx="19" cy="12" r="2" />
                <circle cx="12" cy="5" r="2" />
                <circle cx="12" cy="19" r="2" />
              </svg>
            </button>
          )}

          {!node.session.isMain && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                if (confirmDelete) {
                  onDelete(node.session.filePath)
                  setConfirmDelete(false)
                } else {
                  setConfirmDelete(true)
                }
              }}
              onBlur={() => setConfirmDelete(false)}
              className={`flex-shrink-0 rounded p-0.5 opacity-0 group-hover:opacity-100 transition-colors ${
                confirmDelete
                  ? 'bg-red-600 text-white opacity-100'
                  : 'text-gray-400 hover:text-red-500 hover:bg-gray-100'
              }`}
            >
              {confirmDelete ? (
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              ) : (
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
              )}
            </button>
          )}
        </div>
      </div>

      {isForking && (
        <div
          className="flex items-center gap-1 pl-8 pr-2 py-1"
          onClick={(e) => e.stopPropagation()}
        >
          <input
            autoFocus
            value={forkName}
            onChange={(e) => setForkName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                const trimmed = forkName.trim()
                if (trimmed) {
                  onForkFromEnd(node.session.filePath, trimmed)
                  setIsForking(false)
                  setForkName('')
                }
              }
              if (e.key === 'Escape') {
                setIsForking(false)
                setForkName('')
              }
            }}
            placeholder="Fork name"
            className="flex-1 min-w-0 rounded border border-purple-300 bg-white px-2 py-0.5 text-xs text-gray-900 outline-none focus:border-purple-500"
          />
          <button
            onClick={() => {
              const trimmed = forkName.trim()
              if (trimmed) {
                onForkFromEnd(node.session.filePath, trimmed)
                setIsForking(false)
                setForkName('')
              }
            }}
            disabled={!forkName.trim()}
            className="rounded bg-purple-600 px-2 py-0.5 text-xs font-medium text-white hover:bg-purple-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Fork
          </button>
          <button
            onClick={() => {
              setIsForking(false)
              setForkName('')
            }}
            className="rounded px-1 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 text-xs transition-colors"
            title="Cancel"
          >
            ✕
          </button>
        </div>
      )}

      {hasChildren && isExpanded && (
        <div>
          {node.children.map((child, i) => {
            const childIsActivePath =
              currentSessionPath === child.session.filePath ||
              isDescendantOf(child, currentSessionPath)
            const laterSiblingOnActivePath = node.children
              .slice(i + 1)
              .some(
                (sibling) =>
                  currentSessionPath === sibling.session.filePath ||
                  isDescendantOf(sibling, currentSessionPath)
              )
            const onPath = childIsActivePath || laterSiblingOnActivePath
            const newAncestorLines = [
              ...ancestorLines.map((entry) => ({
                hasLine: entry.hasLine,
                highlight: entry.branchActive
                  ? (entry.highlight && childIsActivePath)
                  : entry.highlight,
                branchActive: entry.branchActive && childIsActivePath,
              })),
              {
                hasLine: i < node.children.length - 1,
                highlight: onPath,
                branchActive: childIsActivePath,
              },
            ]
            return (
              <SessionNode
                key={child.session.filePath}
                node={child}
                ancestorLines={newAncestorLines}
                currentSessionPath={currentSessionPath}
                isOnActivePath={childIsActivePath}
                onSwitch={onSwitch}
                onRename={onRename}
                onDelete={onDelete}
                onSetSessionStatus={onSetSessionStatus}
                onForkFromEnd={onForkFromEnd}
                onContextMenu={onContextMenu}
                triggerRenamePath={triggerRenamePath}
                onRenameTriggered={onRenameTriggered}
                triggerForkPath={triggerForkPath}
                onForkTriggered={onForkTriggered}
              />
            )
          })}
        </div>
      )}
    </div>
  )
}

function SessionSidebar({
  sessions,
  currentSession,
  onSwitchSession,
  onNewSession,
  onRenameSession,
  onDeleteSession,
  onSetSessionStatus,
  onForkFromEnd,
  isCollapsed,
  onToggleCollapse,
}: SessionSidebarProps): React.ReactElement {
  const [isCreating, setIsCreating] = useState(false)
  const [newSessionName, setNewSessionName] = useState('')
  const [sidebarWidth, setSidebarWidth] = useState(() => {
    const saved = localStorage.getItem('xi-sidebar-width')
    const parsed = saved ? parseInt(saved, 10) : 260
    return Number.isNaN(parsed) ? 260 : Math.min(480, Math.max(180, parsed))
  })
  const [isResizing, setIsResizing] = useState(false)
  const [contextMenu, setContextMenu] = useState<{
    x: number
    y: number
    session: SessionInfo
  } | null>(null)
  const [triggerRenamePath, setTriggerRenamePath] = useState<string | null>(null)
  const [triggerForkPath, setTriggerForkPath] = useState<string | null>(null)

  const sidebarWidthRef = useRef(sidebarWidth)
  sidebarWidthRef.current = sidebarWidth

  const resizeStartRef = useRef<{ startX: number; startWidth: number } | null>(null)

  const projects = sessions?.projects ?? []
  const projectName = projects[0]?.projectPath.split('/').pop() ?? 'Sessions'
  const root = projects[0]?.root ?? null

  const handleCreateSession = useCallback(() => {
    const trimmed = newSessionName.trim()
    if (!trimmed) return
    onNewSession(trimmed)
    setNewSessionName('')
    setIsCreating(false)
  }, [newSessionName, onNewSession])

  const handleContextMenu = useCallback((e: React.MouseEvent, session: SessionInfo) => {
    e.preventDefault()
    e.stopPropagation()
    setContextMenu({ x: e.clientX, y: e.clientY, session })
  }, [])

  const handleRenameTriggered = useCallback(() => {
    setTriggerRenamePath(null)
  }, [])

  const handleForkTriggered = useCallback(() => {
    setTriggerForkPath(null)
  }, [])

  useEffect(() => {
    if (!contextMenu) return

    const handleClick = () => setContextMenu(null)
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setContextMenu(null)
    }

    document.addEventListener('click', handleClick)
    document.addEventListener('keydown', handleKeyDown)

    return () => {
      document.removeEventListener('click', handleClick)
      document.removeEventListener('keydown', handleKeyDown)
    }
  }, [contextMenu])

  useEffect(() => {
    if (!isResizing) return

    const handleMouseMove = (e: MouseEvent) => {
      if (!resizeStartRef.current) return
      const delta = e.clientX - resizeStartRef.current.startX
      const newWidth = Math.min(480, Math.max(180, resizeStartRef.current.startWidth + delta))
      setSidebarWidth(newWidth)
    }

    const handleMouseUp = () => {
      setIsResizing(false)
      resizeStartRef.current = null
      localStorage.setItem('xi-sidebar-width', String(sidebarWidthRef.current))
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }

    document.body.style.cursor = 'col-resize'
    document.body.style.userSelect = 'none'
    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('mouseup', handleMouseUp)

    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('mouseup', handleMouseUp)
    }
  }, [isResizing])

  const handleResizeStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault()
    setIsResizing(true)
    resizeStartRef.current = { startX: e.clientX, startWidth: sidebarWidth }
  }, [sidebarWidth])

  if (isCollapsed) {
    return (
      <div className="flex flex-col items-center w-12 bg-gray-50 border-r border-gray-200 pt-10 pb-3">
        <button
          onClick={onToggleCollapse}
          className="rounded p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
          title="Expand sidebar"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M13 5l7 7-7 7M5 5l7 7-7 7" />
          </svg>
        </button>
      </div>
    )
  }

  return (
    <div
      className="relative flex flex-col bg-gray-50 border-r border-gray-200 overflow-hidden"
      style={{ width: `${sidebarWidth}px` }}
    >
      <div className="flex items-center justify-between px-3 pt-10 pb-3 border-b border-gray-200">
        <span className="text-xs font-semibold uppercase tracking-wider text-gray-500 truncate">{projectName}</span>
        <div className="flex items-center gap-1 flex-shrink-0">
          <button
            onClick={() => { setIsCreating(true); setNewSessionName('') }}
            className="rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="New session"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
            </svg>
          </button>
          <button
            onClick={onToggleCollapse}
            className="rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="Collapse sidebar"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M11 19l-7-7 7-7M19 19l-7-7 7-7" />
            </svg>
          </button>
        </div>
      </div>

      {isCreating && (
        <div className="flex items-center gap-1 border-b border-gray-200 px-3 py-2">
          <input
            autoFocus
            value={newSessionName}
            onChange={(e) => setNewSessionName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') handleCreateSession()
              if (e.key === 'Escape') setIsCreating(false)
            }}
            placeholder="Session name"
            className="flex-1 min-w-0 rounded border border-gray-300 bg-white px-2 py-1 text-xs text-gray-900 outline-none focus:border-blue-500"
          />
          <button
            onClick={handleCreateSession}
            disabled={!newSessionName.trim()}
            className="rounded bg-blue-600 px-2 py-1 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Create
          </button>
        </div>
      )}

      <div className="flex-1 overflow-y-auto py-2">
        {projects.length === 0 || !root ? (
          <div className="px-3 py-6 text-center text-xs text-gray-600">
            No sessions found
          </div>
        ) : (
          <SessionNode
            node={root}
            ancestorLines={[]}
            currentSessionPath={currentSession?.filePath ?? null}
            isOnActivePath={true}
            onSwitch={onSwitchSession}
            onRename={onRenameSession}
            onDelete={onDeleteSession}
            onSetSessionStatus={onSetSessionStatus}
            onForkFromEnd={onForkFromEnd}
            onContextMenu={handleContextMenu}
            triggerRenamePath={triggerRenamePath}
            onRenameTriggered={handleRenameTriggered}
            triggerForkPath={triggerForkPath}
            onForkTriggered={handleForkTriggered}
          />
        )}
      </div>

      <div
        className="absolute top-0 right-0 w-1 h-full cursor-col-resize hover:w-1.5 hover:bg-blue-500/30 transition-all z-10"
        onMouseDown={handleResizeStart}
      />

      {contextMenu && (
        <div
          className="fixed z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 text-xs min-w-[140px]"
          style={{ left: contextMenu.x, top: contextMenu.y }}
          onClick={(e) => e.stopPropagation()}
        >
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              setTriggerRenamePath(contextMenu.session.filePath)
              setContextMenu(null)
            }}
          >
            Rename
          </div>
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              const newStatus = contextMenu.session.status === 'completed' ? 'active' : 'completed'
              onSetSessionStatus(contextMenu.session.filePath, newStatus)
              setContextMenu(null)
            }}
          >
            {contextMenu.session.status === 'completed' ? 'Mark as active' : 'Mark as completed'}
          </div>
          {contextMenu.session.parentSessionPath && (
            <div
              className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
              onClick={() => {
                onSwitchSession(contextMenu.session.parentSessionPath!)
                setContextMenu(null)
              }}
            >
              Go to parent
            </div>
          )}
          {contextMenu.session.filePath === currentSession?.filePath && (
            <div
              className="px-3 py-1.5 hover:bg-purple-50 cursor-pointer text-purple-600"
              onClick={() => {
                setTriggerForkPath(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Fork
            </div>
          )}
          {!contextMenu.session.isMain && (
            <div
              className="px-3 py-1.5 hover:bg-red-50 cursor-pointer text-red-600"
              onClick={() => {
                onDeleteSession(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Delete
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default SessionSidebar

